104→function CancelFlow({
105→  open,
106→  submitting,
107→  onPause,
108→  onCancel,
109→  onClose,
110→}: {
111→  open: boolean;
112→  submitting: boolean;
113→  onPause: () => void;
114→  onCancel: () => void;
115→  onClose: () => void;
116→}) {
117→  const ref = useRef<HTMLDialogElement>(null);
118→  const [step, setStep] = useState<1 | 2>(1);
119→  const [reason, setReason] = useState<string>(CANCEL_REASONS[0]);
120→  const [prevOpen, setPrevOpen] = useState(false);
121→
122→  // Reset to step 1 whenever the dialog opens (React-recommended prop→state pattern)
123→  if (open && !prevOpen) {
124→    setPrevOpen(true);
125→    setStep(1);
126→    setReason(CANCEL_REASONS[0]);
127→  } else if (!open && prevOpen) {
128→    setPrevOpen(false);
129→  }
130→
131→  useEffect(() => {
132→    const el = ref.current;
133→    if (!el) return;
134→    if (open && !el.open) el.showModal();
135→    if (!open && el.open) el.close();
136→  }, [open]);
137→
138→  const handleDialogCancel = useCallback(
139→    (e: React.SyntheticEvent) => {
140→      e.preventDefault();
141→      onClose();
142→    },
143→    [onClose],
144→  );
145→
146→  if (!open) return null;
147→
148→  return (
149→    <dialog
150→      ref={ref}
151→      onCancel={handleDialogCancel}
152→      className="fixed inset-0 z-50 m-auto max-w-sm rounded-2xl border-0 bg-white p-6 shadow-xl backdrop:bg-black/30"
153→    >
154→      {step === 1 ? (
